CREATE TABLE "PollOption" ("id" TEXT NOT NULL,"label" TEXT NOT NULL,"sortOrder" INTEGER NOT NULL,"active" BOOLEAN NOT NULL DEFAULT true,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "PollOption_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "PollOption_sortOrder_key" ON "PollOption"("sortOrder");
CREATE TABLE "PollVote" ("id" TEXT NOT NULL,"optionId" TEXT NOT NULL,"customModel" TEXT,"ipHash" TEXT NOT NULL,"cookieHash" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "PollVote_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "PollVote_cookieHash_key" ON "PollVote"("cookieHash"); CREATE INDEX "PollVote_ipHash_idx" ON "PollVote"("ipHash");
CREATE TABLE "InterestRegistration" ("id" TEXT NOT NULL,"email" TEXT NOT NULL,"name" TEXT,"preferredModel" TEXT NOT NULL,"contactHandle" TEXT,"consent" BOOLEAN NOT NULL,"contacted" BOOLEAN NOT NULL DEFAULT false,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "InterestRegistration_pkey" PRIMARY KEY ("id")); CREATE UNIQUE INDEX "InterestRegistration_email_key" ON "InterestRegistration"("email");
CREATE TABLE "VisitorQuestion" ("id" TEXT NOT NULL,"displayName" TEXT,"question" TEXT NOT NULL,"answer" TEXT,"approved" BOOLEAN NOT NULL DEFAULT false,"published" BOOLEAN NOT NULL DEFAULT false,"rejected" BOOLEAN NOT NULL DEFAULT false,"ipHash" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "VisitorQuestion_pkey" PRIMARY KEY ("id")); CREATE INDEX "VisitorQuestion_approved_published_createdAt_idx" ON "VisitorQuestion"("approved","published","createdAt");
CREATE TABLE "SiteSetting" ("key" TEXT NOT NULL,"value" TEXT NOT NULL,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "SiteSetting_pkey" PRIMARY KEY ("key"));
CREATE TABLE "AdminActionLog" ("id" TEXT NOT NULL,"action" TEXT NOT NULL,"targetId" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "AdminActionLog_pkey" PRIMARY KEY ("id"));
ALTER TABLE "PollVote" ADD CONSTRAINT "PollVote_optionId_fkey" FOREIGN KEY ("optionId") REFERENCES "PollOption"("id") ON DELETE CASCADE ON UPDATE CASCADE;
